// Split the string by underscores
let parts = '{{blog}}'.split('_');

// Capitalize first letter of each word and join with spaces
let formatted = parts
  .map((part, index) => {
    // Skip capitalization for the last part if it's a number
    if (index === parts.length - 1 && !isNaN(part)) {
      return part;
    }
    // Capitalize first letter
    return part.charAt(0).toUpperCase() + part.slice(1).toLowerCase();
  })
  .join(' ');

return formatted;

 return new Promise(async (resolve, reject) => {   
    const data = new URLSearchParams();
    data.append('action', 'delete_mail');
    //data.append('email', '{{playgroundsEmail}}');
    data.append('extraFilter', 'subject:"{{Title}}"');

    const response = await fetch(ajax_object.ajax_url, {
        method: 'POST',
